import pandas as pddef filtrar_codigo(dataset):    """    Parameters    ----------    dataset : dataset        Recorre el dataset y filtra las primeras letras del código de Holland. Luego, a cada una la agrega a una serie creada en esta función.    Returns    -------    serie_letras : serie        Crea t devuelve una serie únicamente con las primeras letras de los códigos de Holland del dataset recibido.    """    serie_letras = []    for codigo in dataset["holland_code"]:        primera_letra = codigo[0]        serie_letras.append(primera_letra)    return pd.Series(serie_letras)def filtrar_dataset(dataset):    """    Parameters    ----------    dataset : dataset        Recorre e dataset y crea un dataset nuevo, que solo incluye las métricas relevantes.    Returns    -------    nuevo_datset : dataset        Devuelve un dataset que solo incluye: el ID de la persona, la primera letra de su código de Holland, su carrera elegida y su nivel de satisfacción con esa carrera.    """    nuevo_dataset = pd.DataFrame()    for columna in dataset.columns:        if columna == "id_persona":            nuevo_dataset["id_persona"] = dataset["id_persona"]        elif columna == "holland_code":            nuevo_dataset["holland_code"] = filtrar_codigo(dataset)        elif columna == "carrera_elegida":            nuevo_dataset["carrera_elegida"] = dataset["carrera_elegida"]        elif columna == "nivel_satisfaccion":            nuevo_dataset["nivel_satisfaccion"] = dataset["nivel_satisfaccion"]        else:            continue    return nuevo_datasetdef metricas(nuevo_dataset):    """    Parameters    ----------    nuevo_dataset : dataset        Recibe lo devuelto por filtrar_dataset() y se fija, para cada personalidad, las carreras y el nivel de satisfacción de cada una. Luego, calcula el porcentaje de apariciones de cada carrera y el promedio del nivel de satisfacción. Finalmente, arma un dataset para cada personalidad, mostrando los datos calculados.    Returns    -------    dataset_R, dataset_A, dataset_I, dataset_S, dataset_E, dataset_C    Son los datasets de cada personalidad laboral, mostrando las carreras elegidas, el porcentaje de veces que fueron elegidas y el promedio de satisfacción para cada una.    """        carreras_R = {}    carreras_A = {}    carreras_I = {}    carreras_S = {}    carreras_E = {}    carreras_C = {}        satisfaccion_R = {}    satisfaccion_A = {}    satisfaccion_I = {}    satisfaccion_S = {}    satisfaccion_E = {}    satisfaccion_C = {}        for i in range(len(nuevo_dataset)):        fila = nuevo_dataset.iloc[i]        personalidad = fila["holland_code"]        carrera = fila["carrera_elegida"]        nivel_sat = fila["nivel_satisfaccion"]# para R        if "R" in personalidad:            contador = 0            if carrera in carreras_R:                contador += 1                carreras_R[carrera] = contador                            else:                contador += 1                carreras_R[carrera] = contador                        if carrera in satisfaccion_R:            satisfaccion_R[carrera].append(nivel_sat)        else:            satisfaccion_R[carrera] = [nivel_sat]            # lo mismo para A        if "A" in personalidad:            contador = 0            if carrera in carreras_A:                contador += 1                carreras_A[carrera] = contador                            else:                contador += 1                carreras_A[carrera] = contador                        if carrera in satisfaccion_A:            satisfaccion_A[carrera].append(nivel_sat)        else:            satisfaccion_A[carrera] = [nivel_sat]# idem para I        if "I" in personalidad:            contador = 0            if carrera in carreras_I:                contador += 1                carreras_I[carrera] = contador                            else:                contador += 1                carreras_I[carrera] = contador                        if carrera in satisfaccion_I:            satisfaccion_I[carrera].append(nivel_sat)        else:            satisfaccion_I[carrera] = [nivel_sat]# idem S        if "S" in personalidad:            contador = 0            if carrera in carreras_S:                contador += 1                carreras_S[carrera] = contador                            else:                contador += 1                carreras_S[carrera] = contador                        if carrera in satisfaccion_S:            satisfaccion_S[carrera].append(nivel_sat)        else:            satisfaccion_S[carrera] = [nivel_sat]            #idem E        if "E" in personalidad:            contador = 0            if carrera in carreras_E:                contador += 1                carreras_E[carrera] = contador                            else:                contador += 1                carreras_E[carrera] = contador                        if carrera in satisfaccion_E:            satisfaccion_E[carrera].append(nivel_sat)        else:            satisfaccion_E[carrera] = [nivel_sat]# idem C        if "C" in personalidad:            contador = 0            if carrera in carreras_C:                contador += 1                carreras_C[carrera] = contador                            else:                contador += 1                carreras_C[carrera] = contador                        if carrera in satisfaccion_C:            satisfaccion_C[carrera].append(nivel_sat)        else:            satisfaccion_C[carrera] = [nivel_sat]# construcción de cada dataset    total_R = sum(carreras_R.values())    filas_R = []    for carrera, cantidad in carreras_R.items():        porcentaje = (cantidad/ total_R) * 100        lista_satis = satisfaccion_R[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_R.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_R = pd.DataFrame(filas_R)    total_A = sum(carreras_A.values())    filas_A = []    for carrera, cantidad in carreras_A.items():        porcentaje = (cantidad/ total_A) * 100        lista_satis = satisfaccion_A[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_A.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_A = pd.DataFrame(filas_A)    total_I = sum(carreras_I.values())    filas_I = []    for carrera, cantidad in carreras_I.items():        porcentaje = (cantidad/ total_I) * 100        lista_satis = satisfaccion_I[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_I.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_I = pd.DataFrame(filas_I)        total_S = sum(carreras_S.values())    filas_S = []    for carrera, cantidad in carreras_S.items():        porcentaje = (cantidad/ total_S) * 100        lista_satis = satisfaccion_S[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_S.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_S = pd.DataFrame(filas_S)    total_E = sum(carreras_E.values())    filas_E = []    for carrera, cantidad in carreras_E.items():        porcentaje = (cantidad/ total_E) * 100        lista_satis = satisfaccion_E[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_E.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_E = pd.DataFrame(filas_E)        total_C = sum(carreras_C.values())    filas_C = []    for carrera, cantidad in carreras_C.items():        porcentaje = (cantidad/ total_C) * 100        lista_satis = satisfaccion_C[carrera]        promedio_satis = sum(lista_satis)/ len(lista_satis)        filas_C.append({"carrera": carrera, "porcentaje_cantidad": porcentaje, "promedio_satisfaccion": promedio_satis})    dataset_C = pd.DataFrame(filas_C)        return dataset_R, dataset_A, dataset_I, dataset_S, dataset_E, dataset_C